SELECT EVNT_ID, EVNT_SE, (SELECT CD_NM FROM RDICMMNCD_TB WHERE CD_SE = 'CD100' AND CD_ID = EVNT_SE) AS EVNT_SE_NM, REGEXP_REPLACE("BGNG_DT", '(.{4})(.{2})(.{2})(.{2})(.{2})(.{2})', '\1-\2-\3 \4:\5') AS BGNG_DT , REGEXP_REPLACE("END_DT", '(.{4})(.{2})(.{2})(.{2})(.{2})(.{2})', '\1-\2-\3 \4:\5') AS END_DT , EVNT_CN, EVNT_CN2, WRKR, ATCH_FILE_ID, PROCS_ID, (SELECT PROCS_NM FROM RDIPROCSINFO_TB WHERE PROCS_ID = E.PROCS_ID) AS PROCS_NM, FCLT_ID, (SELECT CD_NM FROM RDICMMNCD_TB WHERE CD_SE = 'CD101' AND CD_ID = FCLT_ID) AS FCLT_NM, FCLT_DTL_ID, ( SELECT CD_NM FROM RDICMMNCD_TB WHERE CD_SE = E.FCLT_ID AND CD_ID = E.FCLT_DTL_ID ) AS FCLT_DTL_NM FROM RDIEVNTMNG_TB E WHERE 1=1
AND EVNT_SE = #{evnt_se}
AND PROCS_ID = #{procs_id}
#{item}
FCLT_ID = #{item.fclt} AND FCLT_DTL_ID = #{item.fclt_dtl}
AND ( (BGNG_DT <= #{bgng_dt} AND #{bgng_dt} <= END_DT) OR (BGNG_DT <= #{end_dt} AND #{end_dt} <= END_DT) OR (#{bgng_dt} <= BGNG_DT AND END_DT <= #{end_dt}) ) ORDER BY BGNG_DT, LAST_MDFCN_DT
